        "id": "maine-elderly-disabilities-waiver",
        "name": "MaineCare Elderly and Adults with Disabilities Waiver",
        "shortName": "Maine EAD Waiver",
        "tagline": "Get comprehensive home care services covered by MaineCare so your parent can stay home instead of entering a nursing facility.",
